import React, { useState } from 'react';
import { User } from '../types';
import { simulateCitation, CitationSimulationResult, AIEngineResponse } from '../services/ai-citation-simulator';
import {
  ArrowLeft, Search, Loader2, Sparkles, Zap, Eye, MessageSquare,
  ThumbsUp, ThumbsDown, Minus, CheckCircle, XCircle, AlertTriangle,
  Lightbulb, Users, BarChart3, Globe,
} from 'lucide-react';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const CREDIT_COST = 6;

const ENGINE_STYLES: Record<string, { color: string; bg: string; gradient: string }> = {
  ChatGPT: { color: 'text-emerald-400', bg: 'bg-emerald-500/10', gradient: 'from-emerald-500/20 to-emerald-600/5' },
  Claude: { color: 'text-orange-400', bg: 'bg-orange-500/10', gradient: 'from-orange-500/20 to-orange-600/5' },
  Perplexity: { color: 'text-blue-400', bg: 'bg-blue-500/10', gradient: 'from-blue-500/20 to-blue-600/5' },
  Gemini: { color: 'text-purple-400', bg: 'bg-purple-500/10', gradient: 'from-purple-500/20 to-purple-600/5' },
};

const MentionBadge: React.FC<{ type: AIEngineResponse['mentionType'] }> = ({ type }) => {
  const styles = {
    direct: { label: 'Mention directe', color: 'text-emerald-400', bg: 'bg-emerald-500/10', icon: CheckCircle },
    indirect: { label: 'Mention indirecte', color: 'text-amber-400', bg: 'bg-amber-500/10', icon: AlertTriangle },
    comparison: { label: 'En comparaison', color: 'text-blue-400', bg: 'bg-blue-500/10', icon: Users },
    absent: { label: 'Non mentionné', color: 'text-red-400', bg: 'bg-red-500/10', icon: XCircle },
  };
  const s = styles[type];
  const Icon = s.icon;
  return (
    <span className={`inline-flex items-center gap-1 text-[10px] font-semibold px-2 py-0.5 rounded-full ${s.bg} ${s.color}`}>
      <Icon size={10} /> {s.label}
    </span>
  );
};

const SentimentIcon: React.FC<{ sentiment: AIEngineResponse['sentiment'] }> = ({ sentiment }) => {
  if (sentiment === 'positive') return <ThumbsUp size={12} className="text-emerald-400" />;
  if (sentiment === 'negative') return <ThumbsDown size={12} className="text-red-400" />;
  return <Minus size={12} className="text-gray-500" />;
};

const EngineCard: React.FC<{ engine: AIEngineResponse; brandName: string }> = ({ engine, brandName }) => {
  const style = ENGINE_STYLES[engine.engine] || ENGINE_STYLES.ChatGPT;
  const [expanded, setExpanded] = useState(true);

  // Highlight brand mentions in the response
  const highlightBrand = (text: string) => {
    if (!brandName) return text;
    const regex = new RegExp(`(${brandName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
    const parts = text.split(regex);
    return parts.map((part, i) =>
      regex.test(part) ? <mark key={i} className="bg-purple-500/30 text-purple-200 rounded px-0.5">{part}</mark> : part
    );
  };

  return (
    <div className="ninja-card overflow-hidden">
      <div className={`bg-gradient-to-r ${style.gradient} px-4 py-3 flex items-center gap-3 border-b border-white/[0.04]`}>
        <div className={`w-8 h-8 rounded-lg ${style.bg} flex items-center justify-center`}>
          <MessageSquare size={14} className={style.color} />
        </div>
        <div className="flex-1">
          <div className="flex items-center gap-2">
            <span className={`text-sm font-bold ${style.color}`}>{engine.engine}</span>
            <MentionBadge type={engine.mentionType} />
          </div>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1">
            <SentimentIcon sentiment={engine.sentiment} />
            <span className="text-xs text-gray-500">{engine.sentiment}</span>
          </div>
          <div className="text-right">
            <span className={`text-lg font-bold ${engine.mentionScore >= 60 ? 'text-emerald-400' : engine.mentionScore >= 30 ? 'text-amber-400' : 'text-red-400'}`}>
              {engine.mentionScore}
            </span>
            <span className="text-[10px] text-gray-500">/100</span>
          </div>
        </div>
      </div>
      <div className="p-4">
        <div className="bg-white/[0.02] rounded-xl p-4 border border-white/[0.04]">
          <p className="text-sm text-gray-300 leading-relaxed italic">"{highlightBrand(engine.response)}"</p>
        </div>
        {engine.excerpt && engine.mentionType !== 'absent' && (
          <div className="mt-3 flex items-start gap-2">
            <Eye size={12} className="text-purple-400 mt-0.5 shrink-0" />
            <p className="text-xs text-gray-500">Extrait : <span className="text-purple-300">"{engine.excerpt}"</span></p>
          </div>
        )}
      </div>
    </div>
  );
};

const AiCitationSimulator: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const [query, setQuery] = useState('');
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [isSimulating, setIsSimulating] = useState(false);
  const [result, setResult] = useState<CitationSimulationResult | null>(null);

  const handleSimulate = async () => {
    if (!query || !brandName || !brandUrl) return;
    const canProceed = onDeductCredits(CREDIT_COST);
    if (!canProceed) return;

    setIsSimulating(true);
    setResult(null);
    try {
      const output = await simulateCitation(query, brandName, brandUrl, industry || undefined);
      setResult(output);
    } catch (err) {
      console.error('Simulation failed:', err);
    } finally {
      setIsSimulating(false);
    }
  };

  const directMentions = result?.engines.filter(e => e.mentionType === 'direct').length || 0;
  const avgScore = result ? Math.round(result.engines.reduce((sum, e) => sum + e.mentionScore, 0) / result.engines.length) : 0;

  return (
    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <button onClick={onBack} className="p-2 rounded-xl hover:bg-white/[0.04] transition-colors">
          <ArrowLeft size={20} className="text-gray-400" />
        </button>
        <div className="flex-1">
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-bold text-white">Simulateur de <span className="gradient-text">Citation IA</span></h1>
            <span className="bg-blue-500/10 text-blue-400 text-xs font-bold px-2.5 py-1 rounded-full border border-blue-500/20 flex items-center gap-1">
              <Sparkles size={10} /> NOUVEAU
            </span>
          </div>
          <p className="text-sm text-gray-500 mt-1">Simulez comment ChatGPT, Claude, Perplexity et Gemini parlent de votre marque</p>
        </div>
      </div>

      {/* Input Form */}
      <div className="ninja-card p-6 mb-8">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1.5">Question à simuler <span className="text-red-400">*</span></label>
            <div className="relative">
              <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" />
              <input value={query} onChange={e => setQuery(e.target.value)}
                placeholder="Quel est le meilleur outil pour optimiser sa visibilité IA ?"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl pl-11 pr-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors"
                onKeyDown={e => e.key === 'Enter' && handleSimulate()} />
            </div>
          </div>
          <div className="grid md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1.5">Votre marque <span className="text-red-400">*</span></label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="CitedBy.ai"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1.5">URL de la marque <span className="text-red-400">*</span></label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://citedby.ai"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1.5">Secteur d'activité</label>
              <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="SaaS, Marketing digital..."
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
            </div>
          </div>
          <button onClick={handleSimulate} disabled={isSimulating || !query || !brandName || !brandUrl}
            className={`w-full md:w-auto px-8 py-3 rounded-xl font-semibold text-sm flex items-center justify-center gap-2 transition-all ${
              isSimulating || !query || !brandName || !brandUrl ? 'bg-gray-700/50 text-gray-500 cursor-not-allowed' : 'btn-gradient text-white'
            }`}>
            {isSimulating ? (<><Loader2 size={16} className="animate-spin" /> Simulation en cours...</>) : (<><Zap size={16} /> Simuler ({CREDIT_COST} Gas)</>)}
          </button>
        </div>
      </div>

      {/* Loading State */}
      {isSimulating && (
        <div className="ninja-card p-12 flex flex-col items-center justify-center text-center mb-8">
          <div className="flex items-center gap-4 mb-6">
            {['ChatGPT', 'Claude', 'Perplexity', 'Gemini'].map((name, i) => {
              const style = ENGINE_STYLES[name];
              return (
                <div key={name} className={`w-12 h-12 rounded-xl ${style.bg} flex items-center justify-center`}
                  style={{ animation: `pulse 1.5s ease-in-out ${i * 0.3}s infinite` }}>
                  <MessageSquare size={20} className={style.color} />
                </div>
              );
            })}
          </div>
          <h3 className="text-lg font-bold text-gray-300 mb-2">Interrogation des IA en cours...</h3>
          <p className="text-sm text-gray-500">Simulation des réponses de 4 moteurs de réponse IA</p>
        </div>
      )}

      {/* Results */}
      {result && !isSimulating && (
        <div className="space-y-6 animate-in fade-in duration-500">
          {/* Score Overview */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div className="ninja-card p-4 text-center">
              <p className={`text-3xl font-bold ${result.overallScore >= 60 ? 'text-emerald-400' : result.overallScore >= 30 ? 'text-amber-400' : 'text-red-400'}`}>
                {result.overallScore}
              </p>
              <p className="text-xs text-gray-500 mt-1">Score global</p>
            </div>
            <div className="ninja-card p-4 text-center">
              <p className="text-3xl font-bold text-purple-400">{directMentions}</p>
              <p className="text-xs text-gray-500 mt-1">Mentions directes</p>
            </div>
            <div className="ninja-card p-4 text-center">
              <p className="text-3xl font-bold text-blue-400">{result.engines.filter(e => e.citationPresent).length}</p>
              <p className="text-xs text-gray-500 mt-1">Citations avec lien</p>
            </div>
            <div className="ninja-card p-4 text-center">
              <p className="text-3xl font-bold text-amber-400">{result.competitorsMentioned.length}</p>
              <p className="text-xs text-gray-500 mt-1">Concurrents cités</p>
            </div>
          </div>

          {/* Query reminder */}
          <div className="ninja-card p-4 flex items-center gap-3 border-l-2 border-purple-500/50">
            <Search size={16} className="text-purple-400 shrink-0" />
            <div>
              <p className="text-xs text-gray-500">Question simulée :</p>
              <p className="text-sm text-gray-300 font-medium">"{result.query}"</p>
            </div>
          </div>

          {/* Engine Responses */}
          <div>
            <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-4">Réponses simulées par moteur</h3>
            <div className="grid md:grid-cols-2 gap-4">
              {result.engines.map((engine, i) => (
                <EngineCard key={i} engine={engine} brandName={result.brandName} />
              ))}
            </div>
          </div>

          {/* Competitors & Improvements */}
          <div className="grid md:grid-cols-2 gap-6">
            {result.competitorsMentioned.length > 0 && (
              <div className="ninja-card p-6">
                <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
                  <Users size={14} className="text-red-400" /> Concurrents mentionnés
                </h3>
                <div className="flex flex-wrap gap-2">
                  {result.competitorsMentioned.map((comp, i) => (
                    <span key={i} className="px-3 py-1.5 bg-red-500/5 border border-red-500/10 rounded-lg text-xs text-red-300 font-medium">
                      {comp}
                    </span>
                  ))}
                </div>
              </div>
            )}
            <div className="ninja-card p-6">
              <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
                <Lightbulb size={14} className="text-amber-400" /> Comment améliorer votre visibilité
              </h3>
              <ul className="space-y-2">
                {result.improvements.map((imp, i) => (
                  <li key={i} className="flex items-start gap-2 text-sm text-gray-400">
                    <span className="text-purple-400 mt-0.5 shrink-0">→</span>
                    {imp}
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      )}

      {/* Empty State */}
      {!result && !isSimulating && (
        <div className="ninja-card p-12 flex flex-col items-center justify-center text-center">
          <div className="flex items-center gap-3 mb-6">
            {Object.entries(ENGINE_STYLES).map(([name, style]) => (
              <div key={name} className={`w-14 h-14 rounded-xl ${style.bg} flex flex-col items-center justify-center gap-1`}>
                <MessageSquare size={18} className={style.color} />
                <span className={`text-[8px] font-bold ${style.color}`}>{name.slice(0, 3)}</span>
              </div>
            ))}
          </div>
          <h3 className="text-lg font-bold text-gray-300 mb-2">Simulateur de Citation</h3>
          <p className="text-sm text-gray-500 max-w-md">Posez une question et découvrez si ChatGPT, Claude, Perplexity et Gemini mentionneraient votre marque dans leur réponse</p>
        </div>
      )}
    </div>
  );
};

export default AiCitationSimulator;

