            </div>
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1.5">Secteur d'activité</label>
              <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="SaaS, Marketing digital..."
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
            </div>
          </div>
          <button onClick={handleSimulate} disabled={isSimulating || !query || !brandName || !brandUrl}
            className={`w-full md:w-auto px-8 py-3 rounded-xl font-semibold text-sm flex items-center justify-center gap-2 transition-all ${
              isSimulating || !query || !brandName || !brandUrl ? 'bg-gray-700/50 text-gray-500 cursor-not-allowed' : 'btn-gradient text-white'
            }`}>
            {isSimulating ? (<><Loader2 size={16} className="animate-spin" /> Simulation en cours...</>) : (<><Zap size={16} /> Simuler ({CREDIT_COST} Gas)</>)}
          </button>
        </div>
      </div>

      {/* Loading State */}
      {isSimulating && (
        <div className="ninja-card p-12 flex flex-col items-center justify-center text-center mb-8">
          <div className="flex items-center gap-4 mb-6">
            {['ChatGPT', 'Claude', 'Perplexity', 'Gemini'].map((name, i) => {
              const style = ENGINE_STYLES[name];
              return (
                <div key={name} className={`w-12 h-12 rounded-xl ${style.bg} flex items-center justify-center`}
                  style={{ animation: `pulse 1.5s ease-in-out ${i * 0.3}s infinite` }}>
                  <MessageSquare size={20} className={style.color} />
                </div>
              );
            })}
          </div>
          <h3 className="text-lg font-bold text-gray-300 mb-2">Interrogation des IA en cours...</h3>
          <p className="text-sm text-gray-500">Simulation des réponses de 4 moteurs de réponse IA</p>
        </div>
      )}

      {/* Results */}
      {result && !isSimulating && (
        <div className="space-y-6 animate-in fade-in duration-500">
          {/* Score Overview */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div className="ninja-card p-4 text-center">
              <p className={`text-3xl font-bold ${result.overallScore >= 60 ? 'text-emerald-400' : result.overallScore >= 30 ? 'text-amber-400' : 'text-red-400'}`}>
                {result.overallScore}
              </p>
              <p className="text-xs text-gray-500 mt-1">Score global</p>
            </div>
            <div className="ninja-card p-4 text-center">
              <p className="text-3xl font-bold text-purple-400">{directMentions}</p>
              <p className="text-xs text-gray-500 mt-1">Mentions directes</p>
            </div>
            <div className="ninja-card p-4 text-center">
              <p className="text-3xl font-bold text-blue-400">{result.engines.filter(e => e.citationPresent).length}</p>
              <p className="text-xs text-gray-500 mt-1">Citations avec lien</p>
            </div>
            <div className="ninja-card p-4 text-center">
              <p className="text-3xl font-bold text-amber-400">{result.competitorsMentioned.length}</p>
              <p className="text-xs text-gray-500 mt-1">Concurrents cités</p>
            </div>
          </div>

          {/* Query reminder */}
          <div className="ninja-card p-4 flex items-center gap-3 border-l-2 border-purple-500/50">
            <Search size={16} className="text-purple-400 shrink-0" />
            <div>
              <p className="text-xs text-gray-500">Question simulée :</p>
              <p className="text-sm text-gray-300 font-medium">"{result.query}"</p>
            </div>
          </div>

          {/* Engine Responses */}
          <div>
            <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-4">Réponses simulées par moteur</h3>
            <div className="grid md:grid-cols-2 gap-4">
              {result.engines.map((engine, i) => (
                <EngineCard key={i} engine={engine} brandName={result.brandName} />
              ))}
            </div>
          </div>

          {/* Competitors & Improvements */}
          <div className="grid md:grid-cols-2 gap-6">
            {result.competitorsMentioned.length > 0 && (
              <div className="ninja-card p-6">
                <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
                  <Users size={14} className="text-red-400" /> Concurrents mentionnés
                </h3>
                <div className="flex flex-wrap gap-2">
                  {result.competitorsMentioned.map((comp, i) => (
                    <span key={i} className="px-3 py-1.5 bg-red-500/5 border border-red-500/10 rounded-lg text-xs text-red-300 font-medium">
                      {comp}
                    </span>
                  ))}
                </div>
              </div>
            )}
            <div className="ninja-card p-6">
              <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
                <Lightbulb size={14} className="text-amber-400" /> Comment améliorer votre visibilité
              </h3>
              <ul className="space-y-2">
                {result.improvements.map((imp, i) => (
                  <li key={i} className="flex items-start gap-2 text-sm text-gray-400">
                    <span className="text-purple-400 mt-0.5 shrink-0">→</span>
                    {imp}
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      )}

      {/* Empty State */}
      {!result && !isSimulating && (
        <div className="ninja-card p-12 flex flex-col items-center justify-center text-center">
          <div className="flex items-center gap-3 mb-6">
            {Object.entries(ENGINE_STYLES).map(([name, style]) => (
              <div key={name} className={`w-14 h-14 rounded-xl ${style.bg} flex flex-col items-center justify-center gap-1`}>
                <MessageSquare size={18} className={style.color} />
                <span className={`text-[8px] font-bold ${style.color}`}>{name.slice(0, 3)}</span>
              </div>
            ))}
          </div>
          <h3 className="text-lg font-bold text-gray-300 mb-2">Simulateur de Citation</h3>
          <p className="text-sm text-gray-500 max-w-md">Posez une question et découvrez si ChatGPT, Claude, Perplexity et Gemini mentionneraient votre marque dans leur réponse</p>
        </div>
      )}
    </div>
  );
};

export default AiCitationSimulator;
